// ── Per-item duplicate check — runs fresh each loop iteration ──
const BLOCKING = ['sent','followup_1','completed','replied','unsubscribed'];

// Current lead from the loop (1 item at a time)
const lead = $('Loop Over Items').item.json;
const leadEmail = (lead['Email'] || '').toLowerCase().trim();

// Check tracking sheet rows
const alreadyTracked = $input.all().some(row => {
  const rowEmail = (row.json['Email'] || row.json['email'] || '').toLowerCase().trim();
  const rowStatus = (row.json['status'] || row.json['Status'] || '').toLowerCase().trim();
  return rowEmail === leadEmail && BLOCKING.includes(rowStatus);
});

if (alreadyTracked) return [];
return [{ json: lead }];
